onClick:
{{
  (async () => {
    // 1. Double-check we actually have a selection
    const recipeId = appsmith.store.activeRecipeID;
    const playerId = appsmith.store.currentUser.id; // Ensure you have the current player's ID

    if (!recipeId) {
      return showAlert("No Schematic Selected!", "warning");
    }

    try {
      // 2. NEW: Patch the Active_Project to PocketBase
      // We do this first so the database is the "Source of Truth"
      await update_active_project.run({ 
        playerId: playerId, 
        recipeId: recipeId 
      });

      // 3. Commit to local store for UI snappiness
      storeValue('activeRecipeID', recipeId);

      // 4. Clear transient UI states
      resetWidget("input_manual", true);

      // 5. Execute the hand-off
      navigateTo('Work Page');

    } catch (error) {
      showAlert("Failed to sync project to server. Check connection.", "error");
    }
  })()
}}
